sql:
SELECT user_id, user_name
FROM users
WHERE user_id NOT IN (SELECT user_id FROM voice_commands);

SELECT user_id, COUNT(*) as number_of_commands
FROM voice_commands
GROUP BY user_id;

SELECT users.user_name, homes.home_address
FROM users
INNER JOIN homes ON users.home_id = homes.home_id;

SELECT COUNT(DISTINCT user_id) AS unique_users
FROM voice_commands
WHERE command_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT user_id, user_name, email, phone_number, email_verified, password, created_at, last_login, home_id, language_preference, voice_id
FROM users
WHERE email_verified = 0 AND home_id IS NOT NULL;

SELECT u.user_name, h.home_address, u.phone_number
FROM users u
INNER JOIN homes h ON u.home_id = h.home_id;

SELECT COUNT(*)
FROM voice_commands
WHERE TIME(command_time) BETWEEN '06:00:00' AND '12:00:00';

SELECT DISTINCT u.email, u.phone_number
FROM users u
JOIN voice_commands vc ON u.user_id = vc.user_id;

SELECT COUNT(DISTINCT user_id) 
FROM voice_commands 
WHERE (strftime('%s', 'now') - strftime('%s', command_date)) < 30 * 24 * 60 * 60;

external_knowledge:
- 'Navigators' refer to the users who execute voice commands;
- 'Set sail more than once' refers to users executing more than one voice command;
- 'Ports of call' are represented by the email addresses of the users;
- 'Average duration they spend at sea' is the average time it takes to execute their commands, converted into minutes.

